class FenwickTree {
    private size: number;
    private tree: number[];

    constructor(n: number) {
        this.size = n;
        this.tree = new Array(n + 1).fill(0);
    }

    update(index: number, delta: number): void {
        let i = index + 1;
        while (i <= this.size) {
            this.tree[i] += delta;
            i += (i & -i);
        }
    }

    prefixQuery(index: number): number {
        let sum = 0;
        let i = index + 1;
        while (i > 0) {
            sum += this.tree[i];
            i -= (i & -i);
        }
        return sum;
    }

    rangeQuery(left: number, right: number): number {
        if (left === 0) {
            return this.prefixQuery(right);
        }
        return this.prefixQuery(right) - this.prefixQuery(left - 1);
    }
}

function popcount(n: number): number {
    let cnt = 0;
    while (n) {
        cnt += n % 2;
        n = Math.floor(n / 2);
