        const depthValue = getDepth(nums[i]);
        currentDepths[i] = depthValue;
        if (depthValue >= 0 && depthValue <= 5) {
            trees[depthValue].update(i, 1);
        }
    }

    const ans: number[] = [];
    for (const q of queries) {
        if (q[0] === 1) {
            const l = q[1], r = q[2], k = q[3];
            if (k <= 5 && k >= 0) {
