                    trees[oldDepth].update(idx, -1);
                }
                if (newDepth >= 0 && newDepth <= 5) {
                    trees[newDepth].update(idx, 1);
                }
                currentDepths[idx] = newDepth;
            }
        }
    }

    return ans;
}
