    const maxN = 1000;
    const smallDepth = new Array(maxN + 1).fill(0);

    function popcount(x: number): number {
        let cnt = 0;
        while (x) {
            x &= x - 1;
            cnt++;
        }
        return cnt;
    }

    for (let i = 1; i <= maxN; i++) {
        if (i === 1) {
            smallDepth[i] = 0;
        } else {
            const cnt = popcount(i);
            smallDepth[i] = smallDepth[cnt] + 1;
        }
    }

    function getDepth(x: number): number {
        if (x === 1) return 0;
        let steps = 0;
        let cur = x;
        while (cur > maxN) {
            cur = popcount(cur);
            steps++;
        }
        return steps + smallDepth[cur];
    }

    class FenwickTree {
        n: number;
        tree: number[];

        constructor(n: number) {
            this.n = n;
            this.tree = new Array(n + 1).fill(0);
        }

