        prefix(i: number): number {
            let sum = 0;
            let idx = i + 1;
            while (idx > 0) {
                sum += this.tree[idx];
                idx -= idx & -idx;
            }
            return sum;
        }

        query(l: number, r: number): number {
            if (l > r) return 0;
            if (l === 0) return this.prefix(r);
            return this.prefix(r) - this.prefix(l - 1);
        }
    }

    const n = nums.length;
    const depths: number[] = new Array(n);
    for (let i = 0; i < n; i++) {
