    const trees: FenwickTree[] = [];
    for (let k = 0; k <= 5; k++) {
        trees.push(new FenwickTree(n));
    }

    for (let i = 0; i < n; i++) {
        const d = depths[i];
        if (d <= 5) {
            trees[d].update(i, 1);
        }
    }

    const ans: number[] = [];

    for (const q of queries) {
        if (q[0] === 1) {
            const l = q[1];
            const r = q[2];
            const k_val = q[3];
